package com.grit.liferecorder.data.repository
import com.grit.liferecorder.core.date.*; import com.grit.liferecorder.data.local.dao.*; import com.grit.liferecorder.data.local.entity.*; import kotlinx.coroutines.flow.*; import java.time.*

class CategoryRepository(private val dao:CategoryDao){ fun observeAll()=dao.observeAll(); suspend fun seedDefaults(){ if(dao.count()==0){ val now=TimeUtils.now(); dao.insertAll(listOf("Personal","Work","Health","Money","Learning","Home","Business","Vehicle","Other").mapIndexed{ i,n->CategoryEntity(name=n,colorKey="default_$i",isDefault=true,createdAt=now,updatedAt=now)}) } } suspend fun add(name:String,color:String="custom")=dao.insert(CategoryEntity(name=name,colorKey=color,createdAt=TimeUtils.now(),updatedAt=TimeUtils.now())) }
class ProjectRepository(private val dao:ProjectDao){ fun observeAll()=dao.observeAll(); suspend fun add(name:String,description:String?=null,categoryId:Long?=null)=dao.insert(ProjectEntity(name=name,description=description,categoryId=categoryId,createdAt=TimeUtils.now(),updatedAt=TimeUtils.now())) }
class TaskRepository(private val dao:TaskDao){ fun observeAll()=dao.observeAll(); fun observeForDate(date:String)=dao.observeForDate(date,DateUtils.millisForStartOfDay(date),DateUtils.millisForStartOfDay(date)+86_399_999); fun observeStats()=dao.observeStats(); suspend fun save(task:TaskEntity)=if(task.id==0L) dao.insert(task.copy(createdAt=TimeUtils.now(),updatedAt=TimeUtils.now())) else {dao.update(task.copy(updatedAt=TimeUtils.now())); task.id}; suspend fun complete(task:TaskEntity){ val now=TimeUtils.now(); dao.update(task.copy(status="Completed",completedAt=now,updatedAt=now)) }; suspend fun cancel(task:TaskEntity){ val now=TimeUtils.now(); dao.update(task.copy(status="Canceled",canceledAt=now,updatedAt=now)) }; suspend fun delete(task:TaskEntity)=dao.delete(task) }
class HabitRepository(private val actionDao:TrackedActionDao, private val logDao:ActionLogDao){ fun observeActions()=actionDao.observeAll(); fun observeLogsForDate(date:String)=logDao.observeForDate(date); fun observeLogs()=logDao.observeAll(); suspend fun save(action:TrackedActionEntity)=if(action.id==0L) actionDao.insert(action.copy(createdAt=TimeUtils.now(),updatedAt=TimeUtils.now())) else {actionDao.update(action.copy(updatedAt=TimeUtils.now())); action.id}; suspend fun log(action:TrackedActionEntity,label:String=action.defaultLabel,note:String?=null,loggedAt:Long=TimeUtils.now())=logDao.insert(ActionLogEntity(trackedActionId=action.id,localDate=DateUtils.fromMillis(loggedAt),loggedAt=loggedAt,label=label,note=note,createdAt=TimeUtils.now(),updatedAt=TimeUtils.now())) }
class RoutineRepository(private val routineDao:RoutineDao, private val stepDao:RoutineStepDao, private val occurrenceDao:RoutineOccurrenceDao){ fun observeRoutines()=routineDao.observeAll(); fun observeOccurrences()=occurrenceDao.observeAll(); fun observeOccurrencesForDate(date:String)=occurrenceDao.observeForDate(date); fun observeSteps(id:Long)=stepDao.observeForRoutine(id); suspend fun save(routine:RoutineEntity,steps:List<String> = emptyList()):Long{ val id=if(routine.id==0L) routineDao.insert(routine.copy(createdAt=TimeUtils.now(),updatedAt=TimeUtils.now())) else { routineDao.update(routine.copy(updatedAt=TimeUtils.now())); routine.id }; if(steps.isNotEmpty()){ stepDao.deleteForRoutine(id); val now=TimeUtils.now(); stepDao.insertAll(steps.mapIndexed{idx,title->RoutineStepEntity(routineId=id,title=title,stepOrder=idx,createdAt=now,updatedAt=now)})}; return id }
 suspend fun completeToday(routine:RoutineEntity,note:String?=null)=setToday(routine,"Completed",completed=true,note=note); suspend fun skipToday(routine:RoutineEntity,note:String?=null)=setToday(routine,"Skipped",skipped=true,note=note); private suspend fun setToday(r:RoutineEntity,status:String,completed:Boolean=false,skipped:Boolean=false,note:String?=null){ val date=DateUtils.today(); val now=TimeUtils.now(); val old=occurrenceDao.get(r.id,date); occurrenceDao.upsert((old?:RoutineOccurrenceEntity(routineId=r.id,localDate=date,createdAt=now,updatedAt=now)).copy(status=status,completedAt=if(completed)now else old?.completedAt,skippedAt=if(skipped)now else old?.skippedAt,note=note?:old?.note,updatedAt=now)) }
 suspend fun markMissedThrough(yesterday:LocalDate=LocalDate.now().minusDays(1)){ val routines=routineDao.active(); if(routines.isEmpty()) return; val now=TimeUtils.now(); val start=yesterday.minusDays(30); var d=start; while(!d.isAfter(yesterday)){ val code=d.dayOfWeek.name.take(3); val date=d.format(DateUtils.iso); routines.filter{it.scheduledDays.split(',').contains(code)}.forEach{ r-> val old=occurrenceDao.get(r.id,date); if(old==null) occurrenceDao.upsert(RoutineOccurrenceEntity(routineId=r.id,localDate=date,status="Missed",missedAt=now,createdAt=now,updatedAt=now)) else if(old.status=="Scheduled") occurrenceDao.upsert(old.copy(status="Missed",missedAt=now,updatedAt=now))}; d=d.plusDays(1) } } }
class JournalRepository(private val dao:JournalDao){ fun observeAll()=dao.observeAll(); fun observeForDate(date:String)=dao.observeForDate(date); suspend fun save(date:String,note:String?,photoPath:String?=null){ require(!note.isNullOrBlank() || !photoPath.isNullOrBlank()); val now=TimeUtils.now(); dao.upsert(JournalEntryEntity(localDate=date,note=note?.takeIf{it.isNotBlank()},photoPath=photoPath,createdAt=now,updatedAt=now)) } }
data class DayAggregate(val date:String,val tasks:List<TaskEntity>,val logs:List<ActionLogEntity>,val routines:List<RoutineOccurrenceEntity>,val journal:JournalEntryEntity?)
class CalendarRepository(private val tasks:TaskDao, private val logs:ActionLogDao, private val routines:RoutineOccurrenceDao, private val journals:JournalDao){ fun observeDay(date:String):Flow<DayAggregate> = combine(tasks.observeForDate(date,DateUtils.millisForStartOfDay(date),DateUtils.millisForStartOfDay(date)+86_399_999),logs.observeForDate(date),routines.observeForDate(date),journals.observeForDate(date)){ t,l,r,j->DayAggregate(date,t,l,r,j)}; fun observeMonth(ym:YearMonth):Flow<List<DayAggregate>>{ val dates=(1..ym.lengthOfMonth()).map{ym.atDay(it).format(DateUtils.iso)}; return combine(dates.map{observeDay(it)}){it.toList()} } }
data class StatsSummary(val totalTasks:Int=0,val completedTasks:Int=0,val overdueTasks:Int=0,val taskCompletionRate:Int=0,val totalLogs:Int=0,val positiveLogs:Int=0,val negativeLogs:Int=0,val neutralLogs:Int=0,val routinesCompleted:Int=0,val routinesSkipped:Int=0,val routinesMissed:Int=0,val journalDays:Int=0,val photoJournalDays:Int=0,val noteJournalDays:Int=0)
class StatsRepository(private val taskDao:TaskDao, private val logDao:ActionLogDao, private val occurrenceDao:RoutineOccurrenceDao, private val journalDao:JournalDao){ fun observe(range:String):Flow<StatsSummary>{ val bounds=when(range){"This week"->DateUtils.weekBounds();"This month"->DateUtils.monthBounds();else->null}; val taskFlow=taskDao.observeStats(); val logFlow=if(bounds==null) logDao.observeAll() else logDao.observeBetween(bounds.first,bounds.second); val routineFlow=if(bounds==null) occurrenceDao.observeAll() else occurrenceDao.observeBetween(bounds.first,bounds.second); val journalFlow=if(bounds==null) journalDao.observeAll() else journalDao.observeBetween(bounds.first,bounds.second); return combine(taskFlow,logFlow,routineFlow,journalFlow){t,l,r,j-> val open=t.count{it.status=="Open"}; val comp=t.count{it.status=="Completed"}; StatsSummary(t.size,comp,t.count{it.status=="Open" && it.completeByDate!=null && it.completeByDate < DateUtils.today()}, if(t.isEmpty())0 else comp*100/t.size,l.size,l.count{it.label=="Positive"},l.count{it.label=="Negative"},l.count{it.label=="Neutral"},r.count{it.status=="Completed"},r.count{it.status=="Skipped"},r.count{it.status=="Missed"},j.size,j.count{it.photoPath!=null},j.count{!it.note.isNullOrBlank()}) } } }
